    json.dump(data, f, indent=2)
# Compare
with open('baseline-packages.json') as f:
    baseline = json.load(f)

# Build lookup: {project_basename: {framework: {pkg_id: resolved_version}}}
def build_lookup(d):
    result = {}
    for p in d['projects']:
        name = p['path'].rsplit('/', 1)[-1]
        result[name] = {}
        for fw in p['frameworks']:
            tfm = fw['framework']
            result[name][tfm] = {}
            for pkg in fw['topLevelPackages']:
                result[name][tfm][pkg['id']] = pkg['resolvedVersion']
    return result

b = build_lookup(baseline)
a = build_lookup(data)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for tfm in sorted(set(list(b.get(proj, {}).keys()) + list(a.get(proj, {}).keys()))):
        bp = b.get(proj, {}).get(tfm, {})
        ap = a.get(proj, {}).get(tfm, {})
        for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
            bv = bp.get(pkg)
            av = ap.get(pkg)
